// ── PropStream CSV Parser & Field Mapper ──
// Reads raw CSV from webhook body, parses it, and maps
// PropStream column names → standard schema fields.

const rawBody = $input.first().json.body;
const marketParam = $input.first().json.query?.market || 'unknown';

if (!rawBody) {
  throw new Error('No CSV body received. Send CSV as raw text in POST body.');
}

// --- Simple CSV parser (handles quoted fields with commas) ---
function parseCSV(text) {
  const lines = text.trim().split(/\r?\n/);
  if (lines.length < 2) throw new Error('CSV must have a header row and at least one data row.');

  const headers = parseCSVLine(lines[0]);
  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    if (!lines[i].trim()) continue;
    const values = parseCSVLine(lines[i]);
    const row = {};
    headers.forEach((h, idx) => { row[h.trim()] = (values[idx] || '').trim(); });
    rows.push(row);
  }
  return rows;
}

function parseCSVLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (inQuotes) {
      if (ch === '"' && line[i + 1] === '"') { current += '"'; i++; }
      else if (ch === '"') { inQuotes = false; }
      else { current += ch; }
    } else {
      if (ch === '"') { inQuotes = true; }
      else if (ch === ',') { result.push(current); current = ''; }
      else { current += ch; }
    }
  }
  result.push(current);
  return result;
}

// --- Parse ---
const records = parseCSV(rawBody);

// --- Map PropStream columns → standard schema ---
const mapped = records.map((r, idx) => {
  const ownerFirst = r['Owner 1 First Name'] || '';
  const ownerLast = r['Owner 1 Last Name'] || '';
  const ownerOccupied = (r['Owner Occupied'] || '').toUpperCase();
  const estLTV = parseFloat(r['Est. Loan-to-Value']) || 0;
  const estEquity = r['Est. Equity'] || '';
  const estValue = r['Est. Value'] || '';
  const foreclosureFactor = r['Foreclosure Factor'] || '';

  return {
    json: {
      row_index: idx + 1,
      market: marketParam,

      // Core property
      property_address: r['Address'] || '',
      unit: r['Unit #'] || '',
      city: r['City'] || '',
      state: r['State'] || '',
      zip: r['Zip'] || '',
      county: r['County'] || '',
      apn: r['APN'] || '',

      // Owner
      owner_name: (ownerFirst + ' ' + ownerLast).trim(),
      owner_first: ownerFirst,
      owner_last: ownerLast,
      owner_2_first: r['Owner 2 First Name'] || '',
      owner_2_last: r['Owner 2 Last Name'] || '',

      // Mailing
      owner_mailing_address: r['Mailing Address'] || '',
      owner_mailing_unit: r['Mailing Unit #'] || '',
      owner_mailing_city: r['Mailing City'] || '',
      owner_mailing_state: r['Mailing State'] || '',
      owner_mailing_zip: r['Mailing Zip'] || '',
      owner_out_of_state: ownerOccupied === 'YES' ? false : true,

      // Financials
      assessed_value: estValue,
      estimated_equity: estEquity,
      estimated_equity_pct: estLTV > 0 ? Math.round(100 - estLTV) : null,
      total_assessed_value: r['Total Assessed Value'] || '',
      last_sale_date: r['Last Sale Recording Date'] || '',
      last_sale_amount: r['Last Sale Amount'] || '',
      open_loans: r['Total Open Loans'] || '',
      est_remaining_balance: r['Est. Remaining balance of Open Loans'] || '',
      est_ltv: r['Est. Loan-to-Value'] || '',

      // Property details
      property_type: r['Property Type'] || '',
      beds: r['Bedrooms'] || '',
      total_baths: r['Total Bathrooms'] || '',
      sqft: r['Building Sqft'] || '',
      lot_sqft: r['Lot Size Sqft'] || '',
      year_built: r['Effective Year Built'] || '',

      // Condition
      total_condition: r['Total Condition'] || '',
      interior_condition: r['Interior Condition'] || '',
      exterior_condition: r['Exterior Condition'] || '',
      bathroom_condition: r['Bathroom Condition'] || '',
      kitchen_condition: r['Kitchen Condition'] || '',

      // Contact
      phone_primary: r['Phone 1'] || '',
      phone_1_type: r['Phone 1 Type'] || '',
      phone_1_dnc: r['Phone 1 DNC'] || '',
      phone_2: r['Phone 2'] || '',
      phone_3: r['Phone 3'] || '',
      email_primary: r['Email 1'] || '',
      email_2: r['Email 2'] || '',

      // Indicators
      mls_status: r['MLS Status'] || '',
      mls_date: r['MLS Date'] || '',
      mls_amount: r['MLS Amount'] || '',
      pre_foreclosure: foreclosureFactor,
      lien_amount: r['Lien Amount'] || '',
      do_not_mail: r['Do Not Mail'] || '',
      litigator: r['Litigator'] || '',
      property_status: r['Property Status'] || '',

      // Meta
      marketing_lists: r['Marketing Lists'] || '',
      date_added_to_list: r['Date Added to List'] || '',
      method_of_add: r['Method of Add'] || '',
      notes: r['Notes'] || '',

      // Pipeline (set downstream)
      lead_score: null,
      lead_tier: null,
      outreach_letter: null,
      processed_at: new Date().toISOString()
    }
  };
});

return mapped;

// ── Merge market branches back together ──
// All three market outputs + fallback converge here.
// We tag each lead with market-specific config before scoring.

const items = $input.all();

const marketConfig = {
  phoenix_mf: {
    label: 'Phoenix Multifamily',
    sheetTab: 'Phoenix_MF',
    strategy: 'multifamily_value_add',
    idealProfile: 'Multifamily 5-50 units in Phoenix metro, value-add opportunities with below-market rents or deferred maintenance'
  },
  slc_mf: {
    label: 'Salt Lake City Multifamily',
    sheetTab: 'SLC_MF',
    strategy: 'multifamily_value_add',
    idealProfile: 'Multifamily properties in SLC metro, focus on student housing near universities or workforce housing'
  },
  heber_str: {
    label: 'Heber City STR',
    sheetTab: 'Heber_STR',
    strategy: 'short_term_rental',
    idealProfile: 'Single family or cabin properties in Heber City/Midway area suitable for Airbnb/VRBO, near Deer Valley or Jordanelle'
  },
  unknown: {
    label: 'Unrouted',
    sheetTab: 'Other',
    strategy: 'general',
    idealProfile: 'Investment property with motivated seller indicators'
  }
};

return items.map(item => {
  const market = item.json.market || 'unknown';
  const config = marketConfig[market] || marketConfig['unknown'];
  return {
    json: {
      ...item.json,
      market_label: config.label,
      sheet_tab: config.sheetTab,
      market_strategy: config.strategy,
      ideal_profile: config.idealProfile
    }
  };
});

