// ── Parse Claude scoring response & attach to lead ──

const items = $input.all();
const results = [];

for (const item of items) {
  const lead = item.json;

  // The HTTP Request node returns the Anthropic API response
  // Response is in lead.content[0].text (Anthropic Messages API format)
  let scoreData = {};
  try {
    const responseText = lead.content?.[0]?.text || lead.data?.content?.[0]?.text || '';
    // Strip any markdown fencing if present
    const cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    scoreData = JSON.parse(cleaned);
  } catch (e) {
    scoreData = {
      score: 0,
      tier: 'ERROR',
      reasoning: 'Failed to parse Claude response: ' + e.message,
      estimated_arv: null,
      recommended_offer_pct: null,
      red_flags: ['Parse error'],
      opportunity_notes: ''
    };
  }

  // Merge score data back with original lead data
  // Original lead data was passed through the HTTP Request node context
  results.push({
    json: {
      ...lead,
      lead_score: scoreData.score,
      lead_tier: scoreData.tier,
      score_reasoning: scoreData.reasoning,
      estimated_arv: scoreData.estimated_arv,
      recommended_offer_pct: scoreData.recommended_offer_pct,
      red_flags: (scoreData.red_flags || []).join('; '),
      opportunity_notes: scoreData.opportunity_notes
    }
  });
}

return results;

