// ── Parse Claude outreach response & merge with lead ──

const items = $input.all();
const results = [];

for (const item of items) {
  const lead = item.json;

  let outreach = {};
  try {
    const responseText = lead.content?.[0]?.text || lead.data?.content?.[0]?.text || '';
    const cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    outreach = JSON.parse(cleaned);
  } catch (e) {
    outreach = {
      letter_subject: '',
      letter_body: 'Error generating letter: ' + e.message,
      letter_cta: '',
      sms_template: '',
      email_subject: '',
      email_body: ''
    };
  }

  results.push({
    json: {
      ...lead,
      letter_subject: outreach.letter_subject,
      letter_body: outreach.letter_body,
      letter_cta: outreach.letter_cta,
      sms_template: outreach.sms_template,
      email_subject: outreach.email_subject,
      email_body: outreach.email_body
    }
  });
}

return results;

// ── Build print-ready CSV for direct mail fulfillment ──
// Columns: owner name, mailing address, letter subject, letter body, CTA

const items = $input.all();

// CSV header
const headers = [
  'Owner Name', 'Mailing Address', 'Mailing City', 'Mailing State',
  'Mailing Zip', 'Property Address', 'City', 'State', 'Zip',
  'Lead Score', 'Lead Tier', 'Letter Subject', 'Letter Body',
  'Letter CTA', 'SMS Template', 'Email Subject', 'Email Body',
  'Phone', 'Email'
];

function csvEscape(val) {
  const s = String(val || '');
  if (s.includes(',') || s.includes('"') || s.includes('\n')) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
}

const rows = [headers.map(csvEscape).join(',')];

for (const item of items) {
  const d = item.json;
  rows.push([
    d.owner_name, d.owner_mailing_address, d.owner_mailing_city,
    d.owner_mailing_state, d.owner_mailing_zip,
    d.property_address, d.city, d.state, d.zip,
    d.lead_score, d.lead_tier, d.letter_subject, d.letter_body,
    d.letter_cta, d.sms_template, d.email_subject, d.email_body,
    d.phone_primary, d.email_primary
  ].map(csvEscape).join(','));
}

const csvContent = rows.join('\n');
const market = items[0]?.json?.market || 'unknown';
const date = new Date().toISOString().split('T')[0];

return [{
  json: {
    fileName: `GGC-${market}-outreach-${date}.csv`,
    csvContent: csvContent,
    totalLeads: items.length,
    hotLeads: items.filter(i => i.json.lead_tier === 'HOT').length,
    warmLeads: items.filter(i => i.json.lead_tier === 'WARM').length,
    coldLeads: items.filter(i => i.json.lead_tier === 'COLD').length,
    market: market,
    market_label: items[0]?.json?.market_label || 'Unknown'
  },
  binary: {
    data: {
      data: Buffer.from(csvContent).toString('base64'),
      mimeType: 'text/csv',
      fileName: `GGC-${market}-outreach-${date}.csv`
    }
  }
}];
